const q = $input.first().json.query || {};
const impl = String(q.implementador || '').toLowerCase();
const PORT = { mario:'1208210821231026', hugo:'1207904722398091', carlos:'1212391476899288' };
const CAL = { mario:'m.labrandero@yurest.com', carlos:'c.aparicio@yurest.com', hugo:'h.zalazar@yurest.com' };
const portGid = PORT[impl]; const calId = CAL[impl];
if (!portGid || !calId) { throw new Error('Implementador no valido: ' + impl); }
const hoy = new Date();
const dow = hoy.getDay() || 7;
const lunes = new Date(hoy); lunes.setDate(hoy.getDate() - dow + 1); lunes.setHours(0,0,0,0);
const fin = new Date(lunes); fin.setDate(lunes.getDate() + 7);
return [{ json: {
  impl: impl,
  portUrl: 'https://app.asana.com/api/1.0/portfolios/' + portGid + '/items',
  calUrl: 'https://www.googleapis.com/calendar/v3/calendars/' + encodeURIComponent(calId) + '/events',
  timeMin: lunes.toISOString(), timeMax: fin.toISOString()
} }];

const data = $input.first().json;
const items = (data.data || []).filter(function(p){ return !(p.current_status && p.current_status.color === 'complete'); });
if (!items.length) { return [{ json: { _empty: true } }]; }
return items.map(function(p){ return { json: { gid: p.gid, name: p.name } }; });

const proyectos = $('Projects To Items').all().map(function(x){return x.json;}).filter(function(p){return !p._empty;});
const taskItems = $input.all().map(function(x){return x.json;});
const calItem = $('GET Calendar').first();
const eventos = (calItem && calItem.json && calItem.json.items) ? calItem.json.items : [];
const EST = '1204618651223643';
const STOP = new Set(['el','la','los','las','de','del','y','o','a','en','con','por','para','un','una','al','santa','santo','san','sant','casa','bar','restaurant','restaurante','restaurantes','hotel','hoteles','grupo','grupos','cocina','cocinas','catering','cafe','cafeteria','pizzeria','pizza','burger','burgers','club','sociedad','sa','sl','slu','sas','proyecto','cliente','formacion','sesion','reunion','llamada','escalado','implementacion','seguimiento','onboarding','revision','revisar','central','centrales']);
function norm(s){ return String(s||'').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g,'').replace(/[^a-z0-9 ]/g,' ').replace(/\s+/g,' ').trim(); }
function palabras(n){ return norm(n).split(' ').filter(function(p){return p.length>=4 && !STOP.has(p);}); }
function coincide(sum, pals){ if(!sum||!pals.length) return false; const ne=norm(sum); const c=pals.filter(function(p){return ne.includes(p);}).length; const minN = pals.length===1?1:Math.max(1, Math.ceil(pals.length/2)); return c>=minN; }
function fechaEvt(evt){ const d=new Date((evt.start && (evt.start.dateTime||evt.start.date))||Date.now()); return d.toLocaleString('es-ES',{weekday:'short',day:'2-digit',month:'short',hour:'2-digit',minute:'2-digit'}); }
const resultados = proyectos.map(function(p, i){
  const resp = taskItems[i] || {};
  const tasks = resp.data || [];
  const pend = [];
  for (const t of tasks) {
    const est=(t.custom_fields||[]).find(function(f){return f.gid===EST;});
    if (!t.completed && est && est.number_value>0) pend.push({name:t.name, estimado:est.number_value});
    const subs = t.subtasks || [];
    for (const sub of subs) {
      const se=(sub.custom_fields||[]).find(function(f){return f.gid===EST;});
      if (!sub.completed && se && se.number_value>0) pend.push({name: t.name+' ↳ '+sub.name, estimado: se.number_value});
    }
  }
  const pals = palabras(p.name);
  const agen = [];
  for (const evt of eventos) { if (evt.summary && coincide(evt.summary, pals)) agen.push({titulo: evt.summary, fecha: fechaEvt(evt)}); }
  return { gid:p.gid, name:p.name, pendientes:pend.length, agendadas:agen.length, pendientesList:pend, agendadasList:agen };
});
resultados.sort(function(a,b){ return (b.agendadas+b.pendientes)-(a.agendadas+a.pendientes); });
const totalAgendadas = resultados.reduce(function(s,r){return s+r.agendadas;},0);
const totalPendientes = resultados.reduce(function(s,r){return s+r.pendientes;},0);
return [{ json: { result: { proyectos: resultados, totalProyectos: resultados.length, totalPendientes, totalAgendadas } } }];

const q = $input.first().json.query || {};
const gid = String(q.gid || '');
if (!gid) { throw new Error('Falta gid de proyecto'); }
const impl = String(q.implementador || '').toLowerCase();
const CAL = { mario:'m.labrandero@yurest.com', carlos:'c.aparicio@yurest.com', hugo:'h.zalazar@yurest.com' };
const calId = CAL[impl] || '';
const hoy = new Date();
const dow = hoy.getDay() || 7;
const lunes = new Date(hoy); lunes.setDate(hoy.getDate()-dow+1); lunes.setHours(0,0,0,0);
const fin = new Date(lunes); fin.setDate(lunes.getDate()+7);
return [{ json: {
  gid: gid, desde: q.desde || '', hasta: q.hasta || '', impl: impl, calId: calId,
  projUrl: 'https://app.asana.com/api/1.0/projects/' + gid,
  tasksUrl: 'https://app.asana.com/api/1.0/projects/' + gid + '/tasks',
  calUrl: 'https://www.googleapis.com/calendar/v3/calendars/' + encodeURIComponent(calId || 'primary') + '/events',
  timeMin: lunes.toISOString(), timeMax: fin.toISOString()
} }];

const SHOW='1211792508172622'; const EST='1204618651223643';
const prep=$('Prep Cli').item.json;
const pinfo=$('Project Info Cli').first();
const nombreCliente=(pinfo && pinfo.json && pinfo.json.data && pinfo.json.data.name) || 'Cliente';
const tr=$('GET Tasks Cli').first();
const top=(tr && tr.json && tr.json.data) ? tr.json.data : [];
const tareas=[];
for (const t of top){ tareas.push(t); for (const sub of (t.subtasks||[])){ tareas.push(Object.assign({}, sub, {esSubtarea:true, parentName:t.name})); } }
const desde=prep.desde ? new Date(prep.desde+'T00:00:00') : null;
const hasta=prep.hasta ? new Date(prep.hasta+'T23:59:59') : null;
const sesiones=[]; const pendientes=[]; let show=0, noShow=0, minutosTotales=0;
for (const t of tareas){
  const sf=(t.custom_fields||[]).find(function(f){return f.gid===SHOW;});
  const asistencia=(sf && sf.enum_value) ? sf.enum_value.name : null;
  if (asistencia){
    const fr=t.completed_at ? new Date(t.completed_at) : (t.due_on ? new Date(t.due_on) : null);
    if (desde && fr && fr<desde) continue;
    if (hasta && fr && fr>hasta) continue;
    const fechaCorta=fr ? fr.toLocaleDateString('es-ES',{day:'2-digit',month:'short'}).toUpperCase() : 'S/F';
    const notes=t.notes||'';
    const ym=notes.match(/https?:\/\/(?:www\.)?(?:youtu\.be|youtube\.com)\/\S+/);
    const youtubeUrl=ym ? ym[0] : null;
    const idx=notes.indexOf('\n\n');
    const resumen=idx>-1 ? notes.substring(idx+2) : notes;
    const preview=resumen.split('\n').filter(function(l){return l.trim();}).slice(0,2).join(' ').substring(0,180);
    const ef=(t.custom_fields||[]).find(function(f){return f.gid===EST;});
    const estimado=(ef && ef.number_value) ? ef.number_value : 0;
    const fechaCompleta=fr ? fr.toLocaleDateString('es-ES',{weekday:'long',day:'numeric',month:'long',year:'numeric'}) : 'Sin fecha';
    sesiones.push({ titulo: t.esSubtarea ? (t.parentName+' ↳ '+t.name) : t.name, fechaCorta:fechaCorta, fechaCompleta:fechaCompleta, fechaRef: fr?fr.getTime():0, asistencia:asistencia, duracion: t.actual_time_minutes||0, estimado:estimado, youtubeUrl:youtubeUrl, preview:preview, resumenCompleto:notes, asanaUrl:'https://app.asana.com/0/'+prep.gid+'/'+t.gid });
    if (asistencia==='Show') show++; else if (asistencia==='No Show') noShow++;
    minutosTotales += t.actual_time_minutes||0;
  } else if (!t.completed){
    const ef=(t.custom_fields||[]).find(function(f){return f.gid===EST;});
    if (ef && ef.number_value) pendientes.push({ name: t.esSubtarea ? (t.parentName+' ↳ '+t.name) : t.name, gid:t.gid, estimado:ef.number_value });
  }
}
sesiones.sort(function(a,b){return b.fechaRef-a.fechaRef;});
const totalSesiones=show+noShow;
const showRate=totalSesiones ? Math.round((show/totalSesiones)*100) : 0;
let planificadas=0, ejecutadas=0;
for (const t of tareas){ const ef=(t.custom_fields||[]).find(function(f){return f.gid===EST;}); if (ef && ef.number_value>0) planificadas++; if (t.completed && t.actual_time_minutes>0) ejecutadas++; }
const calItem=$('GET Calendar Cli').first();
const eventos=(calItem && calItem.json && calItem.json.items) ? calItem.json.items : [];
const STOP=new Set(['el','la','los','las','de','del','y','o','a','en','con','por','para','un','una','al','santa','santo','san','sant','casa','bar','restaurant','restaurante','restaurantes','hotel','hoteles','grupo','grupos','cocina','cocinas','catering','cafe','cafeteria','pizzeria','pizza','burger','burgers','club','sociedad','sa','sl','slu','sas','proyecto','cliente','formacion','sesion','reunion','llamada','escalado','implementacion','seguimiento','onboarding','revision','revisar','central','centrales']);
function norm(s){ return String(s||'').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g,'').replace(/[^a-z0-9 ]/g,' ').replace(/\s+/g,' ').trim(); }
function palabras(n){ return norm(n).split(' ').filter(function(p){return p.length>=4 && !STOP.has(p);}); }
function coincide(sum,pals){ if(!sum||!pals.length) return false; const ne=norm(sum); const c=pals.filter(function(p){return ne.includes(p);}).length; const minN=pals.length===1?1:Math.max(1,Math.ceil(pals.length/2)); return c>=minN; }
function fechaEvt(evt){ const d=new Date((evt.start && (evt.start.dateTime||evt.start.date))||Date.now()); return d.toLocaleString('es-ES',{weekday:'short',day:'2-digit',month:'short',hour:'2-digit',minute:'2-digit'}); }
const pals=palabras(nombreCliente);
let agendadasEstaSemana=0; const eventosAgendados=[];
for (const evt of eventos){ if (evt.summary && coincide(evt.summary,pals)){ agendadasEstaSemana++; eventosAgendados.push({titulo:evt.summary, fecha:fechaEvt(evt)}); } }
return [{ json: { result: { nombre:nombreCliente, totalTareas:planificadas, completadas:ejecutadas, totalSesiones:totalSesiones, minutosTotales:minutosTotales, showRate:showRate, sesiones:sesiones, pendientes:pendientes, agendadasEstaSemana:agendadasEstaSemana, eventosAgendados:eventosAgendados } } }];
